function a(e){if(!e)return e;if(e instanceof Date)return new Date(e.getTime()+e.getTimezoneOffset()*60*1e3);if(e.split(/\D/).length===3)throw new Error("Unable to parse "+e);return new Date(e)}function r(e){if(!e)return e;let t=e.split(/\D/).map(n=>parseInt(n));return t[1]=t[1]-1,new Date(...t)}const o=1e3*60*60*24;function D(e){const t=new Date(e);return t.setDate(t.getDate()+1),t}export{o as D,a,D as o,r as p};
